var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"젠장! 끝도 없이 밀려온다!","JPN":"くそ！　次々と押し寄せてくる！","ENG":"Dang it! They won't stop coming!","TWN":"該死！沒完沒了！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"총알이 다 떨어졌어! 이대로는 모두 죽게 생겼다고!","JPN":"弾切れだ！　このままじゃみんな殺される！","ENG":"I'm out of rounds! We're all going to die at this rate!","TWN":"沒子彈了！這樣下去所有人都會死掉的！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"제이크! 뭐 하고 있어! 어서 도망쳐!","JPN":"ジェイク！　何してる！　早く逃げろ！","ENG":"Jake! What are you doing?! Get out of here!","TWN":"傑克！你在幹什麼！快點逃！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"시, 싫어!","JPN":"い、いやだ！","ENG":"N-no!","TWN":"不，不要！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"난 싸울 거야! 할아버지 몫까지 저놈들을 해치우겠어!","JPN":"俺は戦う！　じいさんの分まで奴らを倒す！","ENG":"I'm going to fight! I'll make them pay for what they've done to grandpa!","TWN":"我也要戰鬥！我要為爺爺報仇！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"투정은 그만 부려! 워커 영감님이 그런 꼴 보고 퍽이나 좋아하시겠다!","JPN":"駄々をこねてる場合じゃない！　ウォーカーじいさんがこんな姿を見て喜ぶと思うのか！","ENG":"Now's not the time for your tantrums! Your grandpa won't approve of this, you know!","TWN":"不要無理取鬧了！沃克老爺子看到一定不會高興的！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"제길, 벌써 코앞까지 들이닥쳤잖아!","JPN":"ちくしょう、もう目の前に迫ってきたぞ！","ENG":"Dang it! They're right in our faces already!","TWN":"該死，已經追上來了！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"어서 달려! 미적거리면 버리고 간다!","JPN":"さっさと走れ！　ぐずぐずすると置いていくぞ！","ENG":"Run! We'll leave any stragglers behind!","TWN":"快走！你再拖拖拉拉，我就不管你了！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"갈 테면 가!","JPN":"行っちまえ！","ENG":"Go if you want to run away!","TWN":"你要走就自己走！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"여긴 우리 마을이야! 자기가 사는 데는 자기가 지켜야 한다고 할아버지가 그랬어!","JPN":"ここは俺たちの町だ！　自分の町は自分で守るべきだとじいさんが言っていた！","ENG":"This is our village! Grandpa always said you have to protect your own home!","TWN":"這裡是我們的村莊啊！爺爺說過，自己生活的地方要由自己守護！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"곧 있으면 주 방위군이 올 거야! 그때까지만 버티면 되잖아?","JPN":"間もなく州の防衛軍が来るはずだ！　その時まで持てばいいんだろう？","ENG":"The National Guard will be here soon! We just have to hold out until then!","TWN":"防衛軍馬上就要來了！只要撐到那時候不就行了？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"왜 도망치려는 건데?!","JPN":"どうして逃げようとするんだよ！","ENG":"Why are you trying to run away?!","TWN":"為什麼要逃跑？！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"멍청한 소리 작작 해!","JPN":"寝ぼけたことを言うな！","ENG":"Don't be stupid!","TWN":"別說傻話了！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"알겠어? 우린 끝났다고! 요즘 세상에 어떤 멍청이가 이런 촌동네까지 챙겨 주냐!","JPN":"いいか？　俺たちはもうおしまいなんだよ！\\nこのご時世に、どのアホがこんな田舎町まで気にかけてくれるんだ！","ENG":"Don’t you get it? We're done for! Who'd be stupid enough to take care of a backwater place like this in this time and age?!","TWN":"懂了嗎？這裡已經完蛋了！現在這世上，怎麼可能還有笨蛋會來幫助這種小村莊啊！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"TOWN_NPC_MALE_NULL","text":{"KOREA":"방위군은 도시 지키기에도 벅차! 그건 그냥 영감님이 상황 모르고 한 소리라고!","JPN":"防衛軍は、都市防衛だけで手一杯なんだよ！\\nじいさんが状況を知らずに言ってたことを鵜呑みにするな！","ENG":"The National Guard has their hands full with the cities as it is! Your grandpa just didn't know better!","TWN":"防衛軍光是保護城鎮就已經忙不過來了！老爺子是搞不清楚狀況，才會說出那種話啊！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_CHILD_NULL","text":{"KOREA":"아냐! 분명히 군인들이 올 거야!","JPN":"いや！　必ず軍人たちが来てくれるはずだ！","ENG":"You're wrong! The soldiers will come, no matter what!","TWN":"不對！軍人們肯定會來的！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_CHILD_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};